export function matchPsychologyRules(text = '', context = {}) {
  const normalizedText = String(text || '').toLowerCase()
  const barrier = String(context.barrier || '').toLowerCase()
  const stage = String(context.stage || '').toLowerCase()

  return psychologyRegistry
    .map((item) => {
      const triggerHits = item.triggers.filter((trigger) => normalizedText.includes(String(trigger).toLowerCase()))
      const tagHits = item.tags.filter((tag) => normalizedText.includes(String(tag).toLowerCase()) || barrier.includes(String(tag).toLowerCase()) || stage.includes(String(tag).toLowerCase()))
      const barrierHit = barrier && (item.title.toLowerCase().includes(barrier) || item.triggers.some((trigger) => barrier.includes(String(trigger).toLowerCase())))
      const signalScore = triggerHits.length * 35 + tagHits.length * 12 + (barrierHit ? 28 : 0)
      const score = signalScore > 0 ? signalScore + Math.round((item.priority || 50) / 10) : 0
      return {
        ...item,
        matchScore: score,
        matchedTriggers: triggerHits,
      }
    })
    .filter((item) => item.matchScore > 0)
    .sort((a, b) => b.matchScore - a.matchScore || b.priority - a.priority)
}

